app.post("/analizar", (req, res, next) => {
  upload.single("archivo")(req, res, (err) => {
    if (err instanceof multer.MulterError) {
      if (err.code === "LIMIT_FILE_SIZE") {
        return res.status(413).json({ ok: false, error: "Archivo demasiado grande. Maximo 50 MB." });
      }
      return res.status(400).json({ ok: false, error: "Error al recibir archivo: " + err.message });
    } else if (err) {
      return res.status(500).json({ ok: false, error: "Error del servidor: " + err.message });
    }
    handleAnalysis(req, res);
  });
});

async function handleAnalysis(req, res) {
  try {
    if (!req.file) return res.status(400).json({ error: "No se recibió archivo" });
    const { originalname, mimetype, buffer, size } = req.file;
    const ext = originalname.split(".").pop().toLowerCase();
    const sizeMB = (size / 1024 / 1024).toFixed(2);
    const base64 = buffer.toString("base64");

    const pxAncho = req.body.px_ancho ? parseInt(req.body.px_ancho) : null;
    const pxAlto = req.body.px_alto ? parseInt(req.body.px_alto) : null;
    const dpiMeta = req.body.dpi_meta ? parseInt(req.body.dpi_meta) : null;
    const mmAncho = req.body.mm_ancho ? parseInt(req.body.mm_ancho) : null;
    const mmAlto = req.body.mm_alto ? parseInt(req.body.mm_alto) : null;
    const cmAncho = req.body.cm_ancho ? parseFloat(req.body.cm_ancho) : null;
    const cmAlto = req.body.cm_alto ? parseFloat(req.body.cm_alto) : null;
    const paginas = req.body.paginas ? parseInt(req.body.paginas) : 1;

    const visuales = ["png", "jpg", "jpeg", "gif", "bmp", "webp"];
    const esPDF = ext === "pdf";
    const esVisual = visuales.includes(ext);

    let ctx = "";
    if (cmAncho && cmAlto) ctx = "Medidas: " + cmAncho + "x" + cmAlto + " cm" + (dpiMeta ? ", DPI: " + dpiMeta : "") + ".";

    const sys = 'Experto preflight imprenta digital. JSON sin backticks. ' + ctx + ' Analiza modo color, sangria, transparencias. DETECCION DE CRUCES DE CORTE — DEFINICION ESTRICTA: Una CRUZ DE CORTE es un par de pequeñas lineas perpendiculares (forma de L, T o cruz +) ubicadas EXCLUSIVAMENTE en las 4 ESQUINAS exteriores del area de impresion, fuera del diseño. Son lineas DELGADAS, NEGRAS o grises, MUY CORTAS (3-5mm), que indican donde el operario debe cortar el papel. NO SON cruces de corte: (a) lineas con flechas o cotas que indican medidas (ej: lineas verticales largas con numeros como 940 mm o 25 mm), (b) marcos rectangulares completos alrededor del diseño, (c) lineas de doblez o pliegue, (d) elementos del propio diseño grafico, (e) bordes decorativos. Si lo que ves son LINEAS DE COTA (con numeros de medida o flechas) → NO son cruces de corte, marca cruces_de_corte.tiene=false. DETECCION DE SANGRIA — REGLA SUPER ESTRICTA: La sangria es un EXCEDENTE de fondo que sobresale MAS ALLA de las cruces de corte reales. PASOS OBLIGATORIOS: (1) ¿Hay cruces de corte REALES segun la definicion de arriba (lineas en L/T/+ en las 4 esquinas)? Si NO → sangria.tiene=false Y cruces_de_corte.tiene=false, FIN. (2) Si SI hay cruces de corte reales, ¿el fondo se extiende HACIA AFUERA formando un borde extra 2-5mm? Solo entonces sangria.tiene=true. (3) Si dudas, marca AMBOS como false. La mayoria de archivos de cliente NO tienen ni cruces de corte ni sangria preparada — es lo normal. NO confundas cotas de medicion con cruces de corte: las cotas son lineas largas con numeros y flechas; las cruces son lineas cortas SIN texto en las esquinas. EVALUACION VISUAL DE NITIDEZ — IMPORTANTE: La imagen que recibes puede tener compresión propia del formato de envio que NO existe en el archivo original. NO confundir artefactos de transmision con problemas reales del archivo. Aplica este criterio BALANCEADO: (1) calidad_visual=ALTA por defecto cuando los textos son legibles, las fotos se ven definidas, los iconos tienen contornos claros y no hay pixelacion EVIDENTE. Es el caso mas comun en archivos profesionales. (2) calidad_visual=MEDIA solo si hay pixelacion CLARAMENTE visible en bordes de texto o imagenes (escalones notorios, no sutiles). (3) calidad_visual=BAJA solo con evidencia INDISCUTIBLE: bordes de texto completamente borrosos al punto de afectar legibilidad, artefactos JPEG MUY visibles (bloques de 8x8 evidentes), o imagenes obviamente estiradas/pixeladas. REGLA DE ORO INVERTIDA: si tienes DUDAS sobre si la calidad es buena o no, marca ALTA. Solo bajar la nota cuando el problema es OBVIO incluso para alguien sin experiencia tecnica. Un PDF profesional bien armado, una imagen con buen DPI, o un diseño que se ve nitido a primera vista debe marcarse ALTA. NO penalices por anti-aliasing normal de renderizado. NO penalices por compresion suave de transmision. CRUCES DE CORTE: si tiene cruces, calcula MEDIDA INTERNA en cm en cruces_de_corte.medida_interna_cm ej "10 x 15 cm". JSON: {"resolucion":{"valor_dpi":' + (dpiMeta || "null") + ',"estado":"ok|advertencia|error","detalle":""},"modo_color":{"valor":"CMYK|RGB|Escala de grises|Desconocido","estado":"ok|advertencia|error","detalle":""},"textos_trazados":{"metodo":"","estado":"ok|advertencia|error|no_determinable","detalle":""},"sangria":{"tiene":false,"valor_mm":null,"estado":"ok|advertencia|error","detalle":""},"cruces_de_corte":{"tiene":false,"medida_interna_cm":null,"estado":"ok|advertencia|error","detalle":""},"tamanio":{"px_ancho":' + (pxAncho || "null") + ',"px_alto":' + (pxAlto || "null") + ',"mm_ancho":' + (mmAncho || "null") + ',"mm_alto":' + (mmAlto || "null") + ',"cm_ancho":' + (cmAncho || "null") + ',"cm_alto":' + (cmAlto || "null") + '},"transparencias":{"tiene":false,"estado":"ok|advertencia|error","detalle":""},"perfil_color_icc":{"tiene":false,"perfil":null,"estado":"ok|advertencia|error","detalle":""},"calidad_visual":"alta|media|baja","calidad_general":"alta|media|baja","problemas_criticos":[],"advertencias":[],"tiempo_estimado":{"total_minutos":0,"desglose":{"correccion_color_min":0,"textos_tipografia_min":0,"sangria_corte_min":0,"resolucion_min":0,"revision_final_min":0},"justificacion":""},"resumen":""}';

    let userContent;
    if (esVisual || esPDF) {
      const mediaType = esPDF ? "application/pdf" : mimetype;
      const tipo = esPDF ? "document" : "image";
      userContent = [
        { type: tipo, source: { type: "base64", media_type: mediaType, data: base64 } },
        { type: "text", text: "Analiza preflight imprenta digital. " + originalname + ". " + ctx + " Solo JSON." }
      ];
    } else {
      userContent = "Analiza preflight. " + originalname + ". " + ctx + " Solo JSON.";
    }

    const callClaude = async (retries = 3, delay = 5000) => {
      for (let i = 0; i < retries; i++) {
        const r = await fetch("https://api.anthropic.com/v1/messages", {
          method: "POST",
          headers: { "Content-Type": "application/json", "x-api-key": process.env.ANTHROPIC_API_KEY, "anthropic-version": "2023-06-01" },
          body: JSON.stringify({ model: "claude-sonnet-4-20250514", max_tokens: 1200, system: sys, messages: [{ role: "user", content: userContent }] })
        });
        if (r.ok) return r;
        const err = await r.text();
        if ((r.status === 529 || r.status === 500 || r.status === 503) && i < retries - 1) {
          await new Promise(rr => setTimeout(rr, delay));
          delay = Math.round(delay * 1.5);
          continue;
        }
        throw new Error("Claude API " + r.status + ": " + err);
      }
    };

    const response = await callClaude();
    const data = await response.json();
    const raw = data.content.map(b => b.text || "").join("").trim();
    const match = raw.match(/\{[\s\S]*\}/);
    if (!match) throw new Error("JSON inválido");

    const analisis = JSON.parse(match[0]);

    const t = analisis.tamanio || {};
    if (cmAncho) t.cm_ancho = cmAncho;
    if (cmAlto) t.cm_alto = cmAlto;
    if (mmAncho) t.mm_ancho = mmAncho;
    if (mmAlto) t.mm_alto = mmAlto;
    if (pxAncho) t.px_ancho = pxAncho;
    if (pxAlto) t.px_alto = pxAlto;
    if (dpiMeta && !(analisis.resolucion && analisis.resolucion.valor_dpi)) {
      if (!analisis.resolucion) analisis.resolucion = {};
      analisis.resolucion.valor_dpi = dpiMeta;
    }
    analisis.tamanio = t;
    analisis.archivo = { nombre: originalname, formato: ext.toUpperCase(), tamano_mb: parseFloat(sizeMB), paginas };

    res.json({ ok: true, analisis });
  } catch (error) {
    console.error("Error:", error.message);
    res.status(500).json({ ok: false, error: error.message });
  }
}

